'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import { DragDropContext, Droppable, Draggable, DropResult } from '@hello-pangea/dnd';
import { Project } from '@shared/types/project';
import { Task, TaskStatus } from '@shared/types/task';
import { Loader2, KanbanSquare, ArrowUpRight, Plus, Trash2, X } from 'lucide-react';
import Link from 'next/link';
import { Badge } from '@/components/ui/badge';
import { cn } from '@shared/lib/utils';
import { Card } from '@/components/ui/card';
import { validateDependency } from '../../../../../shared/lib/workflow-validation';


type BoardData = {
    BLOCKED: Task[];
    READY: Task[];
    RUNNING: Task[];
    DONE: Task[];
};

export default function WorkflowBoardPage() {
    const { id } = useParams();
    const [loading, setLoading] = useState(true);
    const [project, setProject] = useState<Project | null>(null);
    const [board, setBoard] = useState<BoardData>({ BLOCKED: [], READY: [], RUNNING: [], DONE: [] });
    const [view, setView] = useState<'kanban' | 'graph'>('kanban');
    const [allTasks, setAllTasks] = useState<Task[]>([]);
    const [userTasks, setUserTasks] = useState<Task[]>([]);
    const [removedAiTaskIds, setRemovedAiTaskIds] = useState<Set<string>>(new Set());
    const [warning, setWarning] = useState<string | null>(null);
    const [showAddModal, setShowAddModal] = useState(false);

    // Load from LocalStorage on mount
    useEffect(() => {
        const localUser = localStorage.getItem(`workflow_user_tasks_${id}`);
        const localRemoved = localStorage.getItem(`workflow_removed_tasks_${id}`);
        if (localUser) setUserTasks(JSON.parse(localUser));
        if (localRemoved) setRemovedAiTaskIds(new Set(JSON.parse(localRemoved)));
    }, [id]);

    // Main hydrator
    useEffect(() => {
        if (!id) return;
        async function fetchInitial() {
            try {
                const res = await fetch(`/api/projects/${id}`);
                if (!res.ok) throw new Error('Failed to fetch project');
                const data = await res.json();
                setProject(data.project);
                setAllTasks(data.tasks || []);
            } catch (error) {
                console.error("Board load error", error);
            } finally {
                setLoading(false);
            }
        }
        fetchInitial();
    }, [id]);

    // Core Compute Logic
    // Core Compute Logic (Hierarchical Graph)
    useEffect(() => {
        const mergeAndCompute = () => {
            // 1. Merge and Normalize into Unified Work Item Model
            let merged: Task[] = [
                ...allTasks.filter(t => !removedAiTaskIds.has(t.id)).map(t => ({
                    ...t,
                    level: t.level ?? 0,
                    meta: { source: 'AI' as const, is_removed: false }
                })),
                ...userTasks.map(t => ({
                    ...t,
                    meta: { source: 'USER' as const, is_removed: false }
                }))
            ];

            // 2. Clean dangling dependencies and parents
            const activeIds = new Set(merged.map(t => t.id));
            merged = merged.map(t => ({
                ...t,
                dependency_task_id: (t.dependency_task_id && activeIds.has(t.dependency_task_id)) ? t.dependency_task_id : undefined,
                parent_task_id: (t.parent_task_id && activeIds.has(t.parent_task_id)) ? t.parent_task_id : undefined
            }));

            // 3. Status Computation Model (Cascade)
            const final = merged.map(t => {
                if (t.status === 'DONE' || t.status === 'RUNNING') return t;
                if (!t.dependency_task_id) return { ...t, status: 'READY' as const };
                const dep = merged.find(d => d.id === t.dependency_task_id);
                return (dep?.status === 'DONE') ? { ...t, status: 'READY' as const } : { ...t, status: 'BLOCKED' as const };
            });

            // 4. Hierarchical Board Grouping
            const newBoard: BoardData = { BLOCKED: [], READY: [], RUNNING: [], DONE: [] };
            final.sort((a, b) => {
                const orderA = a.graph_order || 0;
                const orderB = b.graph_order || 0;
                if (a.parent_task_id === b.id) return 1;
                if (b.parent_task_id === a.id) return -1;
                return orderA - orderB;
            }).forEach(t => {
                if (newBoard[t.status]) newBoard[t.status].push(t);
            });
            setBoard(newBoard);
        };

        if (allTasks.length > 0 || userTasks.length > 0) mergeAndCompute();
    }, [allTasks, userTasks, removedAiTaskIds]);

    const saveLocal = (uTasks: Task[], rIds: Set<string>) => {
        localStorage.setItem(`workflow_user_tasks_${id}`, JSON.stringify(uTasks));
        localStorage.setItem(`workflow_removed_tasks_${id}`, JSON.stringify(Array.from(rIds)));
    };

    const onRemoveTask = (taskId: string) => {
        const isUser = userTasks.some(t => t.id === taskId);
        if (isUser) {
            const next = userTasks.filter(t => t.id !== taskId);
            setUserTasks(next);
            saveLocal(next, removedAiTaskIds);
        } else {
            const next = new Set(removedAiTaskIds);
            next.add(taskId);
            setRemovedAiTaskIds(next);
            saveLocal(userTasks, next);
        }
    };

    const onAddTask = (newTask: Partial<Task>) => {
        const taskId = `user-${Date.now()}`;

        // Step 1: Structural Validation
        if (newTask.dependency_task_id) {
            const result = validateDependency(taskId, newTask.dependency_task_id, [...allTasks, ...userTasks], newTask);
            if (!result.valid) {
                setWarning(result.error || "Graph Validation Error");
                return;
            }
        }

        const fullTask: Task = {
            id: taskId,
            phase_id: allTasks[0]?.phase_id || 'default',
            title: newTask.title || 'Untitled Work Item',
            description: newTask.description || '',
            task_type: newTask.task_type || 'HUMAN',
            status: 'READY',
            task_order: (allTasks.length + userTasks.length + 1) * 10,
            graph_order: (allTasks.length + userTasks.length + 1) * 10,
            dependency_task_id: newTask.dependency_task_id,
            parent_task_id: newTask.parent_task_id,
            level: newTask.parent_task_id ? 1 : 0,
            created_at: new Date().toISOString(),
            meta: { source: 'USER', is_removed: false }
        };

        const next = [...userTasks, fullTask];
        setUserTasks(next);
        saveLocal(next, removedAiTaskIds);
        setShowAddModal(false);
    };

    const onDragEnd = async (result: DropResult) => {
        setWarning(null);
        if (!result.destination) return;
        const { source, destination, draggableId } = result;
        if (source.droppableId === destination.droppableId && source.index === destination.index) return;

        const finishStatus = destination.droppableId as TaskStatus;

        // Update User Task state locally
        const isUser = userTasks.some(t => t.id === draggableId);
        if (isUser) {
            const next = userTasks.map(t => t.id === draggableId ? { ...t, status: finishStatus } : t);
            setUserTasks(next);
            saveLocal(next, removedAiTaskIds);
            return;
        }

        // Persistent update for AI tasks if not demo
        if (!project?.is_demo_project) {
            try {
                await fetch('/api/tasks/status', {
                    method: 'PATCH',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ task_id: draggableId, status: finishStatus })
                });
                // Optimistically update AI task in local state to trigger recompute
                setAllTasks(prev => prev.map(t => t.id === draggableId ? { ...t, status: finishStatus } : t));
            } catch (e) {
                console.error("Status sync failed", e);
            }
        }
    };

    if (loading) {
        return <div className="p-12 text-center text-muted-foreground"><Loader2 className="w-8 h-8 animate-spin mx-auto" /></div>;
    }

    const columns: { id: TaskStatus, title: string, color: string }[] = [
        { id: 'BLOCKED', title: 'Waiting on Dependencies', color: 'border-amber-500/20 bg-amber-500/5' },
        { id: 'READY', title: 'Ready to Start', color: 'border-primary/20 bg-primary/5' },
        { id: 'RUNNING', title: 'In Progress', color: 'border-blue-500/20 bg-blue-500/5' },
        { id: 'DONE', title: 'Completed', color: 'border-emerald-500/20 bg-emerald-500/5' }
    ];

    return (
        <div className="max-w-[1600px] h-[calc(100vh-140px)] flex flex-col mx-auto px-2 relative">
            {warning && (
                <div className="absolute top-0 left-1/2 -translate-x-1/2 z-[100] w-[90%] md:w-[600px] bg-amber-500 border border-amber-600 text-white px-4 py-3 rounded-xl shadow-2xl flex items-center justify-between animate-in fade-in slide-in-from-top-4 duration-300">
                    <div className="flex items-center gap-3">
                        <div className="bg-white/20 p-1 rounded-full text-white">⚠️</div>
                        <p className="text-sm font-bold">{warning}</p>
                    </div>
                    <button onClick={() => setWarning(null)} className="text-white hover:text-white/80 font-bold p-1">✕</button>
                </div>
            )}
            <div className="mb-8 flex items-end justify-between">
                <div>
                    <h1 className="text-page-title flex items-center gap-3">
                        <KanbanSquare className="w-8 h-8 text-primary" />
                        Execution Engine
                    </h1>
                    <div className="text-muted-foreground mt-1 max-w-xl truncate flex items-center gap-2">
                        {project?.title} workflow plan
                        {project?.is_demo_project && <Badge variant="default" className="text-[10px] bg-primary/10 text-primary">Demo</Badge>}
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <button
                        onClick={() => setShowAddModal(true)}
                        className="flex items-center gap-2 bg-primary/10 text-primary px-4 py-1.5 rounded-lg font-bold text-xs hover:bg-primary/20 transition-all border border-primary/20"
                    >
                        <Plus className="w-4 h-4" />
                        Add Work Item
                    </button>
                    <div className="flex bg-muted p-1 rounded-lg">
                        <button
                            onClick={() => setView('kanban')}
                            className={cn("px-4 py-1.5 text-xs font-semibold rounded-md transition-all", view === 'kanban' ? "bg-background shadow-sm text-foreground" : "text-muted-foreground")}
                        >
                            Board
                        </button>
                        <button
                            onClick={() => setView('graph')}
                            className={cn("px-4 py-1.5 text-xs font-semibold rounded-md transition-all", view === 'graph' ? "bg-background shadow-sm text-foreground" : "text-muted-foreground")}
                        >
                            Map
                        </button>
                    </div>
                </div>
            </div>

            {/* Merge logic & Simulation Update: The Board naturally includes both AI and USER items */}
            {view === 'kanban' ? (
                <DragDropContext onDragEnd={onDragEnd}>
                    <div className="flex-1 grid grid-cols-1 md:grid-cols-4 gap-4 overflow-hidden">

                        {columns.map((col) => (
                            <div key={col.id} className={cn("flex flex-col h-full bg-card rounded-xl border p-1 overflow-hidden", col.color)}>
                                <div className="p-3 border-b border-border/40 font-bold text-[11px] uppercase tracking-wider flex items-center justify-between">
                                    {col.title}
                                    <span className="bg-muted px-2 py-0.5 rounded text-[10px] text-muted-foreground">
                                        {board[col.id].length}
                                    </span>
                                </div>

                                <Droppable droppableId={col.id}>
                                    {(provided, snapshot) => (
                                        <div
                                            {...provided.droppableProps}
                                            ref={provided.innerRef}
                                            className={cn(
                                                "flex-1 overflow-y-auto p-2 space-y-3",
                                                snapshot.isDraggingOver ? "bg-muted/30" : "bg-transparent"
                                            )}
                                        >
                                            {board[col.id].map((task, index) => (
                                                <TaskCard
                                                    key={task.id}
                                                    task={task}
                                                    index={index}
                                                    id={id as string}
                                                    isDemo={project?.is_demo_project ?? false}
                                                    allTasks={[...allTasks, ...userTasks]}
                                                    onRemove={() => onRemoveTask(task.id)}
                                                />
                                            ))}
                                            {provided.placeholder}
                                        </div>
                                    )}
                                </Droppable>
                            </div>
                        ))}
                    </div>
                </DragDropContext>
            ) : (
                <div className="flex-1 bg-card rounded-xl border border-border p-8 overflow-y-auto">
                    <div className="max-w-4xl mx-auto space-y-8">
                        <div className="flex items-center gap-4 mb-4">
                            <div className="w-4 h-4 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
                            <h2 className="text-xl font-bold">Dependency Workflow Plan</h2>
                        </div>

                        <div className="relative pl-8 border-l-2 border-dashed border-border/60 space-y-12">
                            {Object.values(board).flat().sort((a, b) => {
                                if (a.parent_task_id === b.id) return 1;
                                if (b.parent_task_id === a.id) return -1;
                                return (a.graph_order || 0) - (b.graph_order || 0);
                            }).map((task, idx) => {
                                const dep = Object.values(board).flat().find(t => t.id === task.dependency_task_id);
                                const parent = Object.values(board).flat().find(t => t.id === task.parent_task_id);
                                return (
                                    <div key={task.id} className={cn("relative group", task.level === 1 ? "ml-12" : "")}>
                                        <div className={cn(
                                            "absolute top-6 w-5 h-5 rounded-full bg-background border-2 z-10 flex items-center justify-center text-[10px] font-bold",
                                            task.level === 1 ? "-left-[89px] border-border text-muted-foreground" : "-left-[41px] border-primary"
                                        )}>
                                            {task.level === 1 ? "↳" : idx + 1}
                                        </div>
                                        <Card className={cn(
                                            "p-5 border-l-4",
                                            task.status === 'DONE' ? "border-l-emerald-500 opacity-60" :
                                                task.status === 'READY' ? "border-l-primary shadow-md scale-[1.02]" :
                                                    task.status === 'RUNNING' ? "border-l-blue-500 animate-pulse" : "border-l-amber-500/40",
                                            task.level === 1 ? "bg-muted/30" : ""
                                        )}>
                                            <div className="flex justify-between items-start">
                                                <div className="space-y-1">
                                                    <div className="flex flex-wrap items-center gap-2">
                                                        <Badge variant={task.status === 'DONE' ? 'success' : 'default'} className={cn("text-[9px] uppercase font-bold tracking-widest", task.status === 'BLOCKED' ? "bg-amber-500/20 text-amber-700 hover:bg-amber-500/30 border-amber-500/30 text-[8px]" : "")}>
                                                            {task.status === 'BLOCKED' ? `Waiting on Dependencies${dep ? ` (depends on ${dep.title})` : ''}` : task.status === 'READY' ? 'Ready to Start' : task.status === 'RUNNING' ? 'In Progress' : 'Completed'}
                                                        </Badge>
                                                        <span className="text-sm font-bold">{task.title}</span>
                                                        {parent && <Badge variant="default" className="text-[8px] opacity-70">Part of {parent.title}</Badge>}
                                                    </div>
                                                    <p className="text-xs text-muted-foreground">{task.description}</p>
                                                </div>
                                                <Badge variant={task.task_type === 'AI' ? 'ai' : 'human'} className="uppercase text-[9px] font-bold">
                                                    {task.task_type} {task.level === 1 ? 'SUBTASK' : 'EXECUTION'}
                                                </Badge>
                                            </div>
                                        </Card>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            )}
            {/* Add Task Modal */}
            {showAddModal && (
                <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-background/80 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-card w-full max-w-md border border-border rounded-2xl shadow-2xl overflow-hidden p-6 animate-in zoom-in-95 duration-200">
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="text-xl font-black">Add Manual Work Item</h3>
                            <button onClick={() => setShowAddModal(false)} className="text-muted-foreground hover:text-foreground">
                                <X className="w-5 h-5" />
                            </button>
                        </div>

                        <form className="space-y-4" onSubmit={(e) => {
                            e.preventDefault();
                            const formData = new FormData(e.currentTarget);
                            onAddTask({
                                title: formData.get('title') as string,
                                description: formData.get('description') as string,
                                task_type: formData.get('type') as any,
                                dependency_task_id: formData.get('dep') as string || undefined,
                                parent_task_id: formData.get('parent') as string || undefined
                            });
                        }}>
                            <div>
                                <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Title</label>
                                <input name="title" required className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none" placeholder="e.g. Code Review" />
                            </div>
                            <div>
                                <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Description</label>
                                <textarea name="description" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none h-24" placeholder="Describe the goal of this task..." />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Type</label>
                                    <select name="type" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none">
                                        <option value="HUMAN">Human</option>
                                        <option value="AI">AI Agent</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Depends On</label>
                                    <select name="dep" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none">
                                        <option value="">No Dependency</option>
                                        {[...allTasks.filter(t => !removedAiTaskIds.has(t.id)), ...userTasks].map(t => (
                                            <option key={t.id} value={t.id}>{t.title}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Parent (Optional)</label>
                                <select name="parent" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none">
                                    <option value="">No Parent (New Task)</option>
                                    {[...allTasks.filter(t => !removedAiTaskIds.has(t.id) && (t.level === 0 || !t.level)), ...userTasks.filter(t => t.level === 0)].map(t => (
                                        <option key={t.id} value={t.id}>{t.title}</option>
                                    ))}
                                </select>
                            </div>
                            <button className="w-full bg-primary text-primary-foreground py-3 rounded-xl font-black uppercase tracking-widest text-xs mt-4 shadow-lg hover:opacity-90 active:scale-95 transition-all">
                                Inject into Workflow
                            </button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

function TaskCard({ task, index, id, isDemo, allTasks, onRemove }: { task: Task, index: number, id: string, isDemo: boolean, allTasks: Task[], onRemove: () => void }) {
    const dep = allTasks.find(t => t.id === task.dependency_task_id);
    const parent = allTasks.find(t => t.id === task.parent_task_id);

    return (
        <Draggable draggableId={task.id} index={index} isDragDisabled={isDemo}>
            {(provided, snapshot) => (
                <div
                    ref={provided.innerRef}
                    {...provided.draggableProps}
                    {...provided.dragHandleProps}
                    className={cn(task.level === 1 ? "ml-6 pl-2 border-l-2 border-primary/10" : "")}
                >
                    <Card
                        className={cn(
                            "group transition-all relative",
                            snapshot.isDragging ? "shadow-xl scale-[1.02] z-50 border-primary" : "hover:border-primary/40",
                            task.status === 'BLOCKED' ? "opacity-60 bg-muted/40" : "",
                            task.status === 'RUNNING' ? "border-blue-500 shadow-blue-500/10 shadow-md" : "",
                            task.level === 1 ? "bg-muted/5 shadow-none" : ""
                        )}
                    >
                        {/* Remove Button */}
                        <button
                            onClick={(e) => { e.stopPropagation(); onRemove(); }}
                            className="absolute top-2 right-2 p-1.5 text-muted-foreground hover:text-destructive opacity-0 group-hover:opacity-100 transition-opacity rounded-md hover:bg-destructive/10 z-10"
                        >
                            <Trash2 className="w-3.5 h-3.5" />
                        </button>

                        <div className="p-5 flex flex-col gap-3">
                            <div className="flex justify-between items-start gap-2">
                                <div className="flex flex-col gap-1.5">
                                    <div className="flex items-center gap-2">
                                        <Badge variant={task.meta?.source === 'USER' ? 'ai' : 'default'} className="text-[8px] px-1.5 py-0 h-4 uppercase font-black tracking-widest bg-primary/5 border-primary/10">
                                            {task.meta?.source || 'AI'} {task.level === 1 ? 'SUBTASK' : 'TASK'}
                                        </Badge>
                                        {parent && (
                                            <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-wider opacity-60">
                                                Part of: {parent.title}
                                            </span>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="text-xl">
                                            {task.task_type === 'AI' ? '🤖' : '👤'}
                                        </span>
                                        <p className="font-semibold text-sm leading-snug line-clamp-2">
                                            {task.title}
                                        </p>
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-wrap gap-2">
                                {task.capability && (
                                    <Badge variant="default" className="text-[10px] h-5 px-2 rounded-[6px] uppercase font-bold tracking-wider bg-secondary text-secondary-foreground hover:bg-secondary/80">
                                        {task.capability}
                                    </Badge>
                                )}
                            </div>

                            {task.reasoning && (
                                <div className="mt-1 p-2.5 bg-muted/40 rounded-lg border border-border/50">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">Reasoning</p>
                                    <p className="text-xs text-foreground/80 leading-relaxed italic line-clamp-2">
                                        "{task.reasoning}"
                                    </p>
                                </div>
                            )}

                            <div className="mt-2 flex items-center justify-between pt-3 border-t border-border/50">
                                <div className="flex items-center gap-2">
                                    {task.status === 'RUNNING' && <Loader2 className="w-3 h-3 animate-spin text-blue-500" />}
                                    <span className={cn(
                                        "text-[9px] font-bold uppercase py-1 px-2 border rounded-full line-clamp-1 break-all tracking-widest",
                                        task.status === 'DONE' ? "bg-success/10 text-success border-success/30" :
                                            task.status === 'READY' ? "bg-primary/10 text-primary border-primary/30" :
                                                task.status === 'RUNNING' ? "bg-blue-500/10 text-blue-600 border-blue-500/30" : "bg-warning/10 text-warning-foreground border-warning/30"
                                    )}>
                                        {task.status === 'BLOCKED' ? `Waiting on Dependencies${dep ? ` (depends on ${dep.title})` : ''}` : task.status === 'READY' ? 'Ready to Start' : task.status === 'RUNNING' ? 'In Progress' : 'Completed'}
                                    </span>
                                </div>
                                <Link
                                    href={`/project/${id}/task/${task.id}`}
                                    className="text-primary font-bold text-[10px] flex items-center gap-1 uppercase tracking-widest hover:underline hover:opacity-80 transition-all bg-primary/5 px-2 py-1 rounded-md"
                                >
                                    Execute
                                    <ArrowUpRight className="w-3 h-3" />
                                </Link>
                            </div>
                        </div>
                    </Card>
                </div>
            )}
        </Draggable>
    );
}

